/*
 * complexlib.h
 *
 */

typedef struct {
    float real;
    float imag;
} complex_t;

complex_t complex(float x, float y);
complex_t polar(float R, float phi);
complex_t add_c(complex_t z1, complex_t z2);
complex_t subtract_c(complex_t z1, complex_t z2);
complex_t multiply_c(complex_t z1, complex_t z2);
complex_t divide_c(complex_t z1, complex_t z2);
complex_t c_conjugate(complex_t z);
complex_t exp_c(complex_t z);
complex_t log_c(complex_t z);
complex_t sqrt_c(complex_t z);

float abs_c(complex_t z);
float phase_c(complex_t z);
float real(complex_t z);
float imaginary(complex_t z);

void display_c(complex_t z);

/*
 * Complex Number Library: complexlib.c
 *
 *  Created by ENGS20!
 *
 *  compile to an object file using
 *  gcc -c -o complexlib.o complexlib.c
 */

#include "complexlib.h"
#include <stdio.h>
#include <math.h>

#define E 2.71828

/* Create a complex number from real and imaginary parts */
complex_t complex(float x, float y)
{
    complex_t z;
    z.real = x;
    z.imag = y;
    return z;
}

/* Create a complex number from polar coordinates */
complex_t polar(float R, float phi)
{
    complex_t z;
    z.real = R * cos(phi);
    z.imag = R * sin(phi);
    return z;
}

/* Extract the real part of a complex number */
float real(complex_t z)
{
    return z.real;
}

/* Extract the imaginary part of a complex number */
float imaginary(complex_t z)
{
    return z.imag;
}

/* Finds the complex conjugate */
complex_t c_conjugate(complex_t z)
{
    complex_t result;
    result.real = z.real;
    result.imag = -z.imag;
    return result;
}

/* add two complex numbers */
complex_t add_c(complex_t z1, complex_t z2)
{
    complex_t result;
    result.real = z1.real + z2.real;
    result.imag = z1.imag + z2.imag;
    return result;
}

/* Subtract complex numbers */
complex_t subtract_c(complex_t z1, complex_t z2)
{
    complex_t result;
    result.real = z1.real - z2.real;
    result.imag = z1.imag - z2.imag;
    return result;
}

/* Multiply complex numbers */
complex_t multiply_c(complex_t z1, complex_t z2)
{
    complex_t result;
    result.real = z1.real * z2.real - z1.imag * z2.imag;
    result.imag = z1.real * z2.imag + z1.imag * z2.real;
    return result;
}

/* Divide complex numbers */
complex_t divide_c(complex_t z1, complex_t z2)
{
    complex_t result;
    float denom = z2.real * z2.real + z2.imag * z2.imag;
    result.real = (z1.real * z2.real + z1.imag * z2.imag) / denom;
    result.imag = (z1.imag * z2.real - z1.real * z2.imag) / denom;
    return result;
}

/* Complex exponential function, using e^(x+iy) = e^x(cos y + i sin y) */
complex_t exp_c(complex_t z)
{
    complex_t result;
    float ex = exp(z.real);
    result.real = ex * cos(z.imag);
    result.imag = ex * sin(z.imag);
    return result;
}

/* Complex logarithm: log(z) = ln(|z|) + i arg(z) */
complex_t log_c(complex_t z)
{
    complex_t result;
    result.real = log(abs_c(z));
    result.imag = phase_c(z);
    return result;
}

/* complex square root: take square root of length and half the angle */
complex_t sqrt_c(complex_t z)
{
    return polar(sqrt(abs_c(z)), phase_c(z) / 2);
}

/* Complex absolute value: |z| = (x*x + y*y)^(1/2) */
float abs_c(complex_t z)
{
    return sqrt(z.real * z.real + z.imag * z.imag);
}

/* argument of a complex number */
float phase_c(complex_t z)
{
    return atan2(z.imag, z.real);
}

/* display a complex number to the console */
void display_c(complex_t z)
{
    printf("%.2f + %.2fi", z.real, z.imag);
}

/* Program to test our complex number library
*
*  testComplex.c
*
* compile this program to an object file using
*     gcc -c -o testComplex.o testComplex.c
*
* then link this object file with the complex number library
*     gcc -o testComplex testComplex.o complexlib.o -lm
*
*/

#include <stdio.h>
#include "complexlib.h"

int main(void) {
	complex_t z,w;

	z = complex(2,3);
	w = complex(-4,-6.5);

	display_c(z);
	printf(" + ");
	display_c(w);
	printf(" = ");
	display_c(add_c(z,w));
	printf("\n");

    return(0);
}
